import collections

def topological_sort(num_nodes: int, edges: list[tuple[int, int]]) -> list[int]:
    graph = collections.defaultdict(list)
    in_degree = [0] * num_nodes

    for u, v in edges:
        graph[u].append(v)
        in_degree[v] += 1

    queue = collections.deque()
    for i in range(num_nodes):
        if in_degree[i] == 0:
            queue.append(i)

    result = []
    while queue:
        u = queue.popleft()
        result.append(u)

        for v in graph[u]:
            in_degree[v] -= 1
            if in_degree[v] == 0:
                queue.append(v)

    if len(result) == num_nodes:
        return result
    else:
        return []
